def find_largest_number(numbers):
    """Finds the largest number in a list."""

    # Check if the input list is not empty to avoid errors.
    if len(numbers) == 0:
        return None

    max_num = numbers[0]  # Assume first element as maximum initially.

    for num in numbers:
        if num > max_num:
            max_num = num  # Update the largest number found so far.

